type paginationPage struct {
	Number  int
	Offset  int
	Current bool
}

// paginationPages returns a sliding window of page numbers centered on the
// current page. Uses clamp-and-shift: centers the window on the current page,
// then shifts it to stay within [1, totalPages], keeping the window full.
func paginationPages(size, offset, total, window int) []paginationPage {
	if size <= 0 || total <= 0 {
		return nil
	}

	totalPages := (total + size - 1) / size
	currentPage := (offset / size) + 1
	if currentPage > totalPages {
		currentPage = totalPages
	}

	window = min(window, totalPages)

	start := max(1, currentPage-(window-1)/2)
	end := start + window - 1
	if end > totalPages {
		end = totalPages
		start = end - window + 1
	}

	pages := make([]paginationPage, 0, window)
	for n := start; n <= end; n++ {
		pages = append(pages, paginationPage{
			Number:  n,
			Offset:  (n - 1) * size,
			Current: n == currentPage,
		})
	}

	return pages
}

func paginationURL(baseURL, query string, offset int) templ.SafeURL {
	params := url.Values{}
	if query != "" {
		params.Set("q", query)
	}
	if offset > 0 {
		params.Set("offset", strconv.Itoa(offset))
	}
	u := baseURL
	if encoded := params.Encode(); encoded != "" {
		u += "?" + encoded
	}
	return templ.SafeURL(u)
}

